import{form,email,senha,adicionarEventoSubmit,limparVal,validarEmail,exibirErrTela,validarSenha,enviarDados,redirecionar,alternarModalMsgs,limparCampo,limparCampos,}from "./utils.min.js";adicionarEventoSubmit(form,async(e)=>{e.preventDefault();const valEmail=limparVal(email.value);const valSenha=limparVal(senha.value);if(!validarEmail(email,valEmail)){exibirErrTela("Erro: O e-mail é obrigatório, deve ser válido e conter até 80 caracteres.",email);return}
if(!validarSenha(senha,valSenha)){exibirErrTela("Erro: A senha é obrigatória e deve conter entre 8 e 30 caracteres, incluindo uma letra minúscula, uma letra maiúscula, um número e um símbolo.",senha);return}
const params={acao:"efetuar_login",email:valEmail,senha:valSenha};const url="efetuar_login.php";const metodo="POST";const{sucesso,dados,msg}=await enviarDados(params,url,metodo);if(sucesso){redirecionar(msg,"painel.html");return}
const{campoErr}=dados;alternarModalMsgs(!0,msg);switch(campoErr){case "email":limparCampo(email);break;case "senha":limparCampo(senha);break;default:limparCampos([email,senha])}})